type iActivityManagerClient struct {
	target binder.Binder
}

func NewIActivityManagerClient(target binder.Binder) IActivityManager {
	if target == nil {
		return nil
	}
	return &iActivityManagerClient{target: target}
}

func (c *iActivityManagerClient) AsBinder() binder.Binder {
	if c == nil {
		return nil
	}
	return c.target
}

func writeIActivityManagerToParcel(p *binder.Parcel, registrar binder.LocalHandlerRegistrar, v IActivityManager) error {
	if v == nil {
		return p.WriteStrongBinder(nil)
	}
	if provider, ok := any(v).(binder.BinderProvider); ok {
		return p.WriteStrongBinder(provider.AsBinder())
	}
	if registrar == nil {
		return fmt.Errorf("%w: no local handler registrar available for IActivityManager", binder.ErrUnsupported)
	}
	b, err := registrar.RegisterLocalHandler(NewIActivityManagerHandlerWithRegistrar(registrar, v))
	if err != nil {
		return err
	}
	return p.WriteStrongBinder(b)
}

func readIActivityManagerFromParcel(p *binder.Parcel) (IActivityManager, error) {
	b, err := p.ReadStrongBinder()
	if err != nil {
		return nil, err
	}
	if b == nil {
		return nil, nil
	}
	return NewIActivityManagerClient(b), nil
}

func WriteIActivityManagerToParcel(p *binder.Parcel, registrar binder.LocalHandlerRegistrar, v IActivityManager) error {
	return writeIActivityManagerToParcel(p, registrar, v)
}

func ReadIActivityManagerFromParcel(p *binder.Parcel) (IActivityManager, error) {
	return readIActivityManagerFromParcel(p)
}

